class Solution:
    def largestRectangleArea(self, heights):
        n = len(heights)
        best = 0
        for i in range(n):
            h = heights[i]
            l = i
            while l > 0 and heights[l - 1] >= h:
                l -= 1
            r = i
            while r < n - 1 and heights[r + 1] >= h:
                r += 1
            best = max(best, h * (r - l + 1))
        return best

