var largestRectangleArea = function(heights) {
    const stack = [];
    let best = 0;
    const h2 = heights.concat([0]);
    for (let i = 0; i < h2.length; i++) {
        const h = h2[i];
        while (stack.length && h2[stack[stack.length - 1]] >= h) {
            const height = h2[stack.pop()];
            const width = stack.length ? i - stack[stack.length - 1] - 1 : i;
            best = Math.max(best, height * width);
        }
        stack.push(i);
    }
    return best;
};
